package com.adoptu.frontend.pages

import com.adoptu.frontend.ApiClientModule
import kotlinx.browser.document
import kotlinx.browser.window
import org.w3c.dom.*

@JsExport
@JsName("PetDetailPage")
object PetDetailPageModule {
    fun init() {
        val id = window.location.pathname.split("/").lastOrNull()
        if (id == null || id.isEmpty()) { window.location.href = "/"; return }

        ApiClientModule.getPet(id).then<Unit> { pet -> renderPetDetail(pet) }
    }

    private fun renderPetDetail(pet: dynamic) {
        val container = document.getElementById("pet-detail")
        if (container != null) {
            container.innerHTML = "<h1>${pet.name}</h1>"
        }
    }
}

@JsExport
@JsName("SheltersPage")
object SheltersPageModule {
    fun init() {
        window.asDynamic().onCountryChange = { onCountryChange() }
        window.asDynamic().searchShelters = { searchShelters() }
        onCountryChange()
    }

    fun onCountryChange() {
        try {
            val country = document.getElementById("search-country")?.unsafeCast<HTMLSelectElement>()?.value ?: ""
            val stateEl = document.getElementById("search-state")?.unsafeCast<HTMLInputElement>()
            val cityEl = document.getElementById("search-city")?.unsafeCast<HTMLInputElement>()
            val zipEl = document.getElementById("search-zip")?.unsafeCast<HTMLInputElement>()
            val neighborhoodEl = document.getElementById("search-neighborhood")?.unsafeCast<HTMLInputElement>()
            val enabled = country.isNotEmpty()
            stateEl?.disabled = !enabled
            cityEl?.disabled = !enabled
            zipEl?.disabled = !enabled
            neighborhoodEl?.disabled = !enabled
            if (!enabled) renderEmpty()
        } catch (e: dynamic) {}
    }

    fun searchShelters() {
        try {
            val country = document.getElementById("search-country")?.unsafeCast<HTMLSelectElement>()?.value ?: ""
            if (country.isEmpty()) {
                renderEmpty()
                return
            }
            val params = mutableListOf<String>()
            params.add("country=$country")
            val state = document.getElementById("search-state")?.unsafeCast<HTMLInputElement>()?.value
            if (!state.isNullOrEmpty()) params.add("state=$state")
            val city = document.getElementById("search-city")?.unsafeCast<HTMLInputElement>()?.value
            if (!city.isNullOrEmpty()) params.add("city=$city")
            val zip = document.getElementById("search-zip")?.unsafeCast<HTMLInputElement>()?.value
            if (!zip.isNullOrEmpty()) params.add("zip=$zip")
            val query = "?" + params.joinToString("&")
            val url = "/api/shelters$query"
            window.asDynamic().fetch(url).then { res ->
                res.json().then { data ->
                    renderShelters(data)
                }
            }.catch { _ ->
                renderEmpty()
            }
        } catch (e: dynamic) {
            renderEmpty()
        }
    }

    private fun renderShelters(shelters: dynamic) {
        try {
            val container = document.getElementById("shelters")
            if (container != null) {
                container.innerHTML = ""
            }
        } catch (e: dynamic) {}
    }

    private fun renderEmpty() {
        try {
            val container = document.getElementById("shelters")
            if (container != null) {
                container.innerHTML = ""
            }
        } catch (e: dynamic) {}
    }
}

@JsExport
@JsName("TemporalHomeSearchPage")
object TemporalHomeSearchPageModule {
    fun init() {
        window.asDynamic().onCountryChange = { onCountryChange() }
        window.asDynamic().searchTemporalHomes = { searchTemporalHomes() }
        onCountryChange()
    }

    fun onCountryChange() {
        try {
            val country = document.getElementById("search-country")?.unsafeCast<HTMLSelectElement>()?.value ?: ""
            val stateEl = document.getElementById("search-state")?.unsafeCast<HTMLInputElement>()
            val cityEl = document.getElementById("search-city")?.unsafeCast<HTMLInputElement>()
            val zipEl = document.getElementById("search-zip")?.unsafeCast<HTMLInputElement>()
            val neighborhoodEl = document.getElementById("search-neighborhood")?.unsafeCast<HTMLInputElement>()
            val enabled = country.isNotEmpty()
            stateEl?.disabled = !enabled
            cityEl?.disabled = !enabled
            zipEl?.disabled = !enabled
            neighborhoodEl?.disabled = !enabled
            if (!enabled) renderEmpty()
        } catch (e: dynamic) {}
    }

    fun searchTemporalHomes() {
        try {
            val country = document.getElementById("search-country")?.unsafeCast<HTMLSelectElement>()?.value ?: ""
            if (country.isEmpty()) { renderEmpty(); return }
            val params = mutableListOf<String>()
            params.add("country=$country")
            val state = document.getElementById("search-state")?.unsafeCast<HTMLInputElement>()?.value
            if (!state.isNullOrEmpty()) params.add("state=$state")
            val url = "/api/temporal-homes?" + params.joinToString("&")
            window.asDynamic().fetch(url).then { res ->
                res.json().then { data -> renderTemporalHomes(data) }
            }.catch { _ -> renderEmpty() }
        } catch (e: dynamic) { renderEmpty() }
    }

    private fun renderTemporalHomes(data: dynamic) {
        val container = document.getElementById("results-container") ?: return
        container.innerHTML = ""
        val arr = if (jsTypeOf(data) == "object" && data.length != undefined) data else arrayOf(data)
        if (arr.length == 0) { container.innerHTML = "<p>No temporal homes found</p>"; return }
        for (i in 0 until arr.length) {
            val th = arr[i]
            val card = document.createElement("div")
            card.className = "temporal-home-card"
            card.innerHTML = "<h3>${th.alias ?: "Temporal Home"}</h3><p>${th.city ?: ""}, ${th.country ?: ""}</p>"
            container.appendChild(card)
        }
    }

    private fun renderEmpty() {
        val container = document.getElementById("results-container")
        container?.innerHTML = ""
    }
}

